pragma solidity ^0.8.0;

contract MockAggregator {
    int256 private _latestAnswer;

    event AnswerUpdated(
        int256 indexed current,
        uint256 indexed roundId,
        uint256 updatedAt
    );

    constructor(
        int256 initialAnswer
    ) {
        _latestAnswer =
            initialAnswer;

        emit AnswerUpdated(
            initialAnswer,
            0,
            block.timestamp
        );
    }

    function latestAnswer()
        external
        view
        returns (int256)
    {
        return _latestAnswer;
    }

    function setLatestAnswer(
        int256 newAnswer
    ) external {
        _latestAnswer =
            newAnswer;

        emit AnswerUpdated(
            newAnswer,
            0,
            block.timestamp
        );
    }

    function getTokenType()
        external
        pure
        returns (uint256)
    {
        return 1;
    }

    function decimals()
        external
        pure
        returns (uint8)
    {
        return 8;
    }
}","keccak256":"0x354b7a7b46ac5251f2ef6cee0fa6a4efac8cf5b608f6d6f238a7b64d4c0a3b4c","license":"BUSL-1.1"}},"version":1}
